import java.util.ArrayList;import java.util.List;import java.util.Map;
final class RetryPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}static final class Scheduler{final List<Integer>delays=new ArrayList<>();void waitFor(int value){delays.add(value);}}@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Scheduler scheduler=new Scheduler();List<Object>outcomes=(List<Object>)input.getOrDefault("outcomes",List.of());int max=((Number)input.get("max_attempts")).intValue(),base=((Number)input.get("base_delay_ms")).intValue(),attempts=0;while(attempts<max){String outcome=attempts<outcomes.size()?String.valueOf(outcomes.get(attempts)):"transient";attempts++;if(outcome.equals("success"))return Map.of("status","success","attempts",attempts,"delays_ms",scheduler.delays);if(outcome.equals("permanent"))throw new PatternException("non_retryable");if(!outcome.equals("transient"))throw new PatternException("unknown_outcome");if(attempts<max)scheduler.waitFor(base<<(attempts-1));}return Map.of("status","exhausted","attempts",attempts,"delays_ms",scheduler.delays);}}
